import React from 'react';
import { useTheme } from './ThemeProvider';

export const ThemeSwitch = () => {
  const { theme, toggleTheme } = useTheme();
  
  return (
    <label className="relative inline-flex items-center cursor-pointer" aria-label="Toggle Theme">
      <input 
        type="checkbox" 
        className="sr-only peer" 
        checked={theme === 'dark'} 
        onChange={toggleTheme} 
      />
      <div className="w-11 h-6 bg-gray-300 peer-focus:outline-none peer-focus:ring-2 peer-focus:ring-[#00c2ff] rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#00c2ff]"></div>
    </label>
  );
};
